```c
#include <stdio.h>
#include <string.h>
#include <netinet/ip.h>
#include <arpa/inet.h>
#include <sys/socket.h>
#include <unistd.h>

// IP伪头部结构体
struct pseudoheader {
    uint32_t source_address;
    uint32_t destination_address;
    uint8_t placeholder;
    uint8_t protocol;
    uint16_t tcp_length;
};

// 计算16位校验和
uint16_t calculate_checksum(uint16_t *data, int length) {
    uint32_t sum = 0;
    while (length > 1) {
        sum += *data++;
        length -= 2;
    }

    // 处理最后剩余的奇数个字节
    if (length == 1) {
        sum += *((uint8_t *)data);
    }

    // 将进位添加到低位
    while (sum >> 16) {
        sum = (sum & 0xFFFF) + (sum >> 16);
    }

    // 取反获得校验和
    return (uint16_t)(~sum);
}

int main() {
    int sock;
    struct sockaddr_in dest_addr;
    char buffer[1024];

    // 创建 socket
    sock = socket(AF_INET, SOCK_RAW, IPPROTO_RAW);
    if (sock == -1) {
        perror("socket");
        return -1;
    }

    // 目标IP地址和端口
    dest_addr.sin_family = AF_INET;
    dest_addr.sin_addr.s_addr = inet_addr("192.168.0.2");
    dest_addr.sin_port = 0;

    // 构建IP头部
    struct iphdr *ip_header = (struct iphdr *)buffer;
    ip_header->ihl = 5;               // IP头部长度（单位：32位字长）
    ip_header->version = 4;           // IP协议版本
    ip_header->tos = 0;               // 服务类型（可以根据需求设置）
    ip_header->tot_len = htons(sizeof(struct iphdr) + strlen("Hello, world!"));  // IP数据报总长度（单位：字节，需使用网络字节序）
    ip_header->id = htons(1234);      // 数据包标识符
    ip_header->frag_off = 0;          // 分片偏移
    ip_header->ttl = 64;              // 生存时间
    ip_header->protocol = IPPROTO_RAW;  // 上层协议（此处设置为原始IP协议）
    ip_header->check = 0;             // 先设置校验和为0

    // 设置源IP地址（可以根据需求设置）
    ip_header->saddr = inet_addr("192.168.0.1");

    // 计算IP头部校验和
    ip_header->check = calculate_checksum((uint16_t *)ip_header, ip_header->ihl * 4);

    // 添加数据内容
    char *data = buffer + sizeof(struct iphdr);
    strcpy(data, "Hello, world!");

    // 发送数据报文
    int send_result = sendto(sock, buffer, ip_header->tot_len, 0, (struct sockaddr *)&dest_addr, sizeof(dest_addr));
    if (send_result == -1) {
        perror("sendto");
        close(sock);
        return -1;
    }
    printf("Sent %d bytes\n", send_result);

    close(sock);
    return 0;
}
```

